/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to an Excel file. LoadWWPContext.Call(&Context)
Do 'OpenDocument'
&CellRow = 1 &FirstColumn = 1
Do 'LoadGridState'
Do 'WriteFilters'
Do 'WriteColumnTitles'
Do 'WriteData'
Do 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'OpenDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&Random = Random() * 10000 &Filename = !"ExportWWFrete-" + &Random.ToString().Trim() + !".xlsx"
&ExcelDocument.Open(&Filename) Do 'CheckStatus' &ExcelDocument.Clear()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not (&FilCod.IsEmpty() AND &FrtCod.IsEmpty() AND &FrtStsFin.IsEmpty() AND &FrtTraCod.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Filial") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &FilCod WWP_ExportWriteFilter(&ExcelDocument, false, &CellRow, &FirstColumn + 2, "Seq.") &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Number = &FrtCod WWP_ExportWriteFilter(&ExcelDocument, false, &CellRow, &FirstColumn + 4, "Fin.") If Not &FrtStsFin.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Text = &FrtStsFin.EnumerationDescription() Endif WWP_ExportWriteFilter(&ExcelDocument, false, &CellRow, &FirstColumn + 6, "Trans.") &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Number = &FrtTraCod EndIf If not (&FrtDtaLct.IsEmpty() AND &FrtDtaLct_To.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Lançados") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &FrtDtaLct WWP_ExportWriteFilter(&ExcelDocument, false, &CellRow, &FirstColumn + 2, "à") &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &FrtDtaLct_To EndIf If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'FRTDTAEMS' &FrtDtaEms1.FromString(&GridStateDynamicFilter.Value) &FrtDtaEms_To1.FromString(&GridStateDynamicFilter.ValueTo) If not &FrtDtaEms1.IsEmpty() OR not &FrtDtaEms_To1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Emissão" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &FrtDtaEms1 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "à" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &FrtDtaEms_To1 EndIf Case &DynamicFiltersSelector1 = !'FRTDOC' &FrtDoc1.FromString(&GridStateDynamicFilter.Value) If not &FrtDoc1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Documento" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&FrtDoc1) EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'FRTDTAEMS' &FrtDtaEms2.FromString(&GridStateDynamicFilter.Value) &FrtDtaEms_To2.FromString(&GridStateDynamicFilter.ValueTo) If not &FrtDtaEms2.IsEmpty() OR not &FrtDtaEms_To2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Emissão" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &FrtDtaEms2 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "à" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &FrtDtaEms_To2 EndIf Case &DynamicFiltersSelector2 = !'FRTDOC' &FrtDoc2.FromString(&GridStateDynamicFilter.Value) If not &FrtDoc2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Documento" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&FrtDoc2) EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'FRTDTAEMS' &FrtDtaEms3.FromString(&GridStateDynamicFilter.Value) &FrtDtaEms_To3.FromString(&GridStateDynamicFilter.ValueTo) If not &FrtDtaEms3.IsEmpty() OR not &FrtDtaEms_To3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Emissão" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &FrtDtaEms3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "à" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &FrtDtaEms_To3 EndIf Case &DynamicFiltersSelector3 = !'FRTDOC' &FrtDoc3.FromString(&GridStateDynamicFilter.Value) If not &FrtDoc3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Documento" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&FrtDoc3) EndIf EndCase EndIf EndIf EndIf &CellRow += 2
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Text = "Lançamento" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "Doc." &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "Filial" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = "Seq." &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Text = "Trans." &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Text = "Nome Transp." &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Text = "Emissao" &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Text = "Vencimento" &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Text = "Financeiro" &ExcelDocument.Cells(&CellRow, &FirstColumn + 9).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 9).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 9).Text = "R$.Frete"
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod FrtDtaLct when &OrderedBy = 1 order FrtDtaLct when &OrderedBy = 2 AND &OrderedDsc = False order (FrtDtaLct) when &OrderedBy = 2 AND &OrderedDsc = True order FrtDoc when &OrderedBy = 3 AND &OrderedDsc = False order (FrtDoc) when &OrderedBy = 3 AND &OrderedDsc = True order FilCod when &OrderedBy = 4 AND &OrderedDsc = False order (FilCod) when &OrderedBy = 4 AND &OrderedDsc = True order FrtCod when &OrderedBy = 5 AND &OrderedDsc = False order (FrtCod) when &OrderedBy = 5 AND &OrderedDsc = True order FrtDtaEms when &OrderedBy = 6 AND &OrderedDsc = False order (FrtDtaEms) when &OrderedBy = 6 AND &OrderedDsc = True order FrtDtaVct when &OrderedBy = 7 AND &OrderedDsc = False order (FrtDtaVct) when &OrderedBy = 7 AND &OrderedDsc = True order FrtStsFin when &OrderedBy = 8 AND &OrderedDsc = False order (FrtStsFin) when &OrderedBy = 8 AND &OrderedDsc = True
using DSWWFrete(&FilCod, &FrtCod, &FrtStsFin, &FrtTraCod, &DynamicFiltersSelector1, &FrtDtaEms1 , &FrtDtaEms_To1, &FrtDoc1, &DynamicFiltersEnabled2, &DynamicFiltersSelector2, &FrtDtaEms2, &FrtDtaEms_To2 , &FrtDoc2, &DynamicFiltersEnabled3, &DynamicFiltersSelector3, &FrtDtaEms3, &FrtDtaEms_To3, &FrtDoc3 , &FrtDtaLct, &FrtDtaLct_To)
// Write cell values &CellRow += 1
Do 'BeforeWriteLine' &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Date = FrtDtaLct &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(FrtDoc) &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Number = FilCod &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Number = FrtCod &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Number = FrtTraCod &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Text = WWP_Export_SecureText(FrtTraRaz) &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Date = FrtDtaEms &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Date = FrtDtaVct &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Text = FrtStsFin.EnumerationDescription() &ExcelDocument.Cells(&CellRow, &FirstColumn + 9).Number = FrtVlrTotFin
Do 'AfterWriteLine'
Endfor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Save() Do 'CheckStatus' &ExcelDocument.Close()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CheckStatus'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If (&ExcelDocument.ErrCode <> 0) &Filename = "" &ErrorMessage = &ExcelDocument.ErrDescription &ExcelDocument.Close() Return EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"WWFreteGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"WWFreteGridState")) Else &GridState.FromXml(&Session.Get(!"WWFreteGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"FILCOD" &FilCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"FRTCOD" &FrtCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"FRTSTSFIN" &FrtStsFin.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"FRTTRACOD" &FrtTraCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"FRTDTALCT" &FrtDtaLct.FromString(&GridStateFilterValue.Value) &FrtDtaLct_To.FromString(&GridStateFilterValue.ValueTo) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'BeforeWriteLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'AfterWriteLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub

	/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */

parm(out:&Filename, out:&ErrorMessage);

